import requests
from flask import Flask, send_file

app = Flask(__name__)

@app.route('/image/<path:url>')
def get_image(url):
    response = requests.get(url)
    return send_file(response.content, mimetype='image/jpeg')

if __name__ == '__main__':
    app.run()